import requests
from dataclasses import dataclass
from typing import Optional


@dataclass
class PolicyDecision:
    allowed: bool
    reason: Optional[str] = None
    redact_fields: list[str] = None

    def __post_init__(self):
        if self.redact_fields is None:
            self.redact_fields = []


class OPAPolicyClient:
    """Client for Open Policy Agent (OPA) REST API."""

    def __init__(self, opa_url: str = "http://localhost:8181"):
        self.opa_url = opa_url

    def evaluate(self, action_context: dict) -> PolicyDecision:
        """
        Send action context to OPA and return an allow/deny decision.

        action_context keys:
          - agent_id: str
          - action_type: str  (e.g. "read_file", "send_email", "delete_record")
          - resource: str
          - data_classification: str  (e.g. "public", "internal", "confidential", "restricted")
          - caller_env: str  (e.g. "prod", "staging", "dev")
        """
        resp = requests.post(
            f"{self.opa_url}/v1/data/agentops/compliance",
            json={"input": action_context},
            timeout=2.0,
        )
        resp.raise_for_status()
        result = resp.json().get("result", {})
        return PolicyDecision(
            allowed=result.get("allow", False),
            reason=result.get("reason"),
            redact_fields=result.get("redact_fields", []),
        )


class PolicyEnforcingAgent:
    """Agent wrapper that enforces policy before every tool call."""

    def __init__(self, policy_client: OPAPolicyClient, agent_id: str):
        self.policy = policy_client
        self.agent_id = agent_id

    def call_tool(self, tool_fn, action_type: str, resource: str,
                  data_classification: str = "internal", **kwargs):
        context = {
            "agent_id": self.agent_id,
            "action_type": action_type,
            "resource": resource,
            "data_classification": data_classification,
            "caller_env": "prod",
        }
        decision = self.policy.evaluate(context)
        if not decision.allowed:
            raise PermissionError(
                f"Policy denied '{action_type}' on '{resource}': {decision.reason}"
            )
        result = tool_fn(**kwargs)
        # Apply field-level redaction if policy requires it
        if decision.redact_fields and isinstance(result, dict):
            for field in decision.redact_fields:
                if field in result:
                    result[field] = "[REDACTED]"
        return result


